INSERT INTO public.innovx_json (company_id, name, json_data) VALUES (1, 'Postman', '{"innovx_master":{"company_name":"Postman","industry":"Software","sub_industry":"API Development & Collaboration Platform","core_business_model":"SaaS platform enabling API design, testing, documentation, and collaboration","target_market":"B2B","geographic_focus":"Global"},"industry_trends":[{"trend_name":"API-First Economy","trend_description":"Organizations are prioritizing APIs as core building blocks for digital transformation and product ecosystems.","time_horizon_years":5,"trend_drivers":["Microservices adoption","Cloud-native development","Platform economy"],"impact_areas":["Product Development","Integration Strategy","Developer Experience"],"strategic_importance":"Critical"},{"trend_name":"AI-Augmented Development","trend_description":"AI copilots are increasingly assisting developers in writing, testing, and maintaining APIs.","time_horizon_years":3,"trend_drivers":["LLMs","Developer productivity tools","Automation demand"],"impact_areas":["Engineering Productivity","Testing Automation","Documentation"],"strategic_importance":"Critical"},{"trend_name":"Shift-Left Testing","trend_description":"Testing is moving earlier in the development lifecycle, emphasizing early validation of APIs.","time_horizon_years":3,"trend_drivers":["DevOps practices","CI/CD pipelines","Quality assurance needs"],"impact_areas":["QA Processes","Release Cycles"],"strategic_importance":"High"},{"trend_name":"Composable Architectures","trend_description":"Enterprises are moving toward modular systems where APIs enable composability and rapid innovation.","time_horizon_years":5,"trend_drivers":["Digital transformation","Headless systems","Marketplace ecosystems"],"impact_areas":["Architecture Design","Integration Layers"],"strategic_importance":"High"},{"trend_name":"API Security & Governance","trend_description":"Rising cyber threats are driving the need for robust API governance, monitoring, and security frameworks.","time_horizon_years":3,"trend_drivers":["Data breaches","Regulatory pressure","API sprawl"],"impact_areas":["Security","Compliance"],"strategic_importance":"Critical"},{"trend_name":"Developer Experience (DX) Platforms","trend_description":"Companies are investing heavily in improving developer onboarding, usability, and productivity tools.","time_horizon_years":4,"trend_drivers":["Talent competition","Platform engineering","Toolchain consolidation"],"impact_areas":["Developer Tools","Adoption Rates"],"strategic_importance":"High"}],"innovation_roadmap":[{"innovation_theme":"AI API Copilot","problem_statement":"Developers spend excessive time writing, testing, and documenting APIs manually.","target_customer":"Software Developers","innovation_type":"Product","time_horizon":"Now","expected_outcome":"Increase developer productivity by 40%","required_capabilities":["LLMs","Code generation","API schema understanding"],"dependent_trend_names":["AI-Augmented Development"]},{"innovation_theme":"API Security Platform","problem_statement":"Organizations lack centralized visibility and control over API vulnerabilities.","target_customer":"Enterprise IT Teams","innovation_type":"Platform","time_horizon":"Next","expected_outcome":"Reduce API security risks","required_capabilities":["Threat detection","Monitoring","Compliance tools"],"dependent_trend_names":["API Security & Governance"]},{"innovation_theme":"Low-Code API Builder","problem_statement":"Non-technical users struggle to build and integrate APIs.","target_customer":"Business Analysts","innovation_type":"Product","time_horizon":"Future","expected_outcome":"Expand user base beyond developers","required_capabilities":["Drag-drop UI","Integration connectors"],"dependent_trend_names":["Composable Architectures"]}],"competitive_landscape":[{"competitor_name":"Swagger (SmartBear)","competitor_type":"Direct","core_strength":"Strong API documentation and design standards","market_positioning":"OpenAPI leader",