":["APIs","SDKs"],"strategic_risks":"Integration challenges","strategic_assumptions":"Apps need built-in analytics"}],"innovx_projects":[{"project_name":"Power BI Copilot Pro","problem_statement":"Users struggle to interpret complex datasets","target_users":"Business analysts","innovation_objective":"AI-driven insights","tier_level":"Tier 1","differentiation_factor":"Natural language insights","aligned_pillar_names":["AI-First Analytics"],"architecture_style":"Microservices","backend_technologies":["Python","FastAPI"],"frontend_technologies":["React","TypeScript"],"ai_ml_technologies":["Azure OpenAI","LangChain"],"data_storage_processing":"Azure SQL + Synapse","integrations_apis":["Microsoft Graph API"],"infrastructure_cloud":"Azure","security_compliance":"AAD, RBAC","primary_use_case":"Ask questions to data","secondary_use_cases":["Auto dashboards"],"scenario_description":"User asks query in plain English","user_journey_summary":"Input -> AI response -> refine","business_value":"Faster decisions","success_metrics":["Query usage","Time saved"]}]}'::jsonb);
