ed insights","aligned_pillar_names":["AI-Driven Personal Finance"],"architecture_style":"AI platform","backend_technologies":["Python"],"frontend_technologies":["React Native"],"ai_ml_technologies":["Recommendation ML"],"data_storage_processing":"Data lake","integrations_apis":["Bank APIs"],"infrastructure_cloud":"AWS","security_compliance":"GDPR","primary_use_case":"Financial advice","secondary_use_cases":["Budgeting"],"scenario_description":"AI guides finances","user_journey_summary":"Analyze -> recommend -> act","business_value":"Engagement","success_metrics":["User retention"]}]}'::jsonb);
INSERT INTO public.job_role_details_json (company_id, company_name, job_role_json) VALUES (1, 'Postman', '{"company_name":"Postman","job_role_details":[{"opportunity_type":"Employment","role_title":"Software Development Engineer (SDE I)","role_category":"SDE","job_description":"Design, develop, and maintain scalable backend and frontend systems for Postman’s API platform. Work on REST APIs, microservices, and cloud-native applications. Collaborate with cross-functional teams to improve API development workflows, optimize performance, and ensure high availability.","compensation":"CTC","ctc_or_stipend":1800000,"bonus":"Performance bonus + ESOPs","benefits_summary":"Health insurance, flexible work hours, remote work support, learning budget, ESOPs","hiring_rounds":[{"round_number":1,"round_name":"Online Assessment","round_category":"Coding Test","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COD","typical_questions":"Implement LRU Cache; Find the longest substring without repeating characters; Merge k sorted linked lists"},{"skill_set_code":"DSA","typical_questions":"Explain time complexity of quicksort; Difference between stack and queue; How does a hash map work internally?"},{"skill_set_code":"APTI","typical_questions":"Probability of drawing specific cards from a deck; Time and work problems; Logical puzzles involving seating arrangement"}]},{"round_number":2,"round_name":"Technical Interview Round 1","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"DSA","typical_questions":"Detect cycle in a linked list; Find median of two sorted arrays; Implement binary search variations"},{"skill_set_code":"OOD","typical_questions":"Design a URL shortener; Explain SOLID principles; Design a parking lot system"},{"skill_set_code":"OS","typical_questions":"What is a deadlock and how to prevent it?; Difference between process and thread; Explain virtual memory"}]},{"round_number":3,"round_name":"Technical Interview Round 2","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"SYSD","typical_questions":"Design a scalable API rate limiter; Design a chat system; How would you scale a REST API?"},{"skill_set_code":"CLOUD","typical_questions":"What is load balancing?; Explain microservices architecture; Difference between IaaS, PaaS, SaaS"},{"skill_set_code":"SWE","typical_questions":"Explain CI/CD pipeline; How do you ensure code quality?; What is version control and branching strategy?"}]},{"round_number":4,"round_name":"HR + Managerial Round","round_category":"Interview","evaluation_type":"HR","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COMM","typical_questions":"Tell me about yourself; Describe a challenging project; Why Postman?"},{"skill_set_code":"SWE","typical_questions":"How do you handle deadlines?; Experience working in teams; Handling production issues"},{"skill_set_code":"APTI","typical_questions":"Situational judgment questions; Decision-making scenarios; Conflict resolution examples"}]}]},{"opportunity_type":"Internship","role_title":"Software Engineer Intern","role_category":"SDE","job_description":"Assist in building and improving Postman’s API tools. Work on frontend/backend tasks, debug issues, write clean code, and collaborate with senior engineers. Exposure to real-world product development and API ecosystems.","compensation":"Stipend","ctc_or_stipend":80000,"bonus":"Performance-based PPO offer","benefits_summary":"Flexible work, mentorship, learning resources, potential PPO","hiring_rounds":[{"round_number":1,"round_name":"Online Coding Test","round_category":"Coding Test","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COD","typical_questions":"Reverse a linked list; Two sum problem; Valid parentheses check"},{"skill_set_code":"DSA","typical_questions":"Explain recursion with example; Difference between array and linked list; Basic tree traversal"},{"skill_set_code":"APTI","typical_questions":"Basic probability questions; Speed-distance-time problems; Number series"}]},{"round_number":2,"round_name":"Technical Interview","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COD","typical_questions":"Find duplicates in array; String compression problem; Rotate matrix"},{"skill_set_code":"OOD","typical_questions":"Design a simple note-taking app; Basics of class and objects; Explain inheritance and polymorphism"},{"skill_set_code":"OS","typical_questions":"What is a thread?; Explain scheduling; Basics of memory management"}]},{"round_number":3,"round_name":"HR Round","round_category":"Interview","evaluation_type":"HR","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COMM","typical_questions":"Why do you want this internship?; Your strengths and weaknesses; Describe a project you worked on"},{"skill_set_code":"SWE","typical_questions":"How do you learn new technologies?; Experience with Git; Working in teams"},{"skill_set_code":"APTI","typical_questions":"Situational questions; Problem-solving approach; Decision making under pressure"}]}]}]}'::jsonb);
INSERT INTO public.job_role_details_json (company_id, company_name, job_role_json) VALUES (2, 'Power BI (Microsoft)', '{"company_name":"Power BI (Microsoft)","job_role_details":[{"opportunity_type":"Employment","role_title":"Data Analyst - Power BI","role_category":"Data_Analyst","job_description":"Develop interactive dashboards and reports using Power BI. Work with large datasets, perform data cleaning, transformation, and modeling. Collaborate with stakeholders to derive business insights and optimize reporting solutions using DAX, SQL, and Azure services.","compensation":"CTC","ctc_or_stipend":1400000,"bonus":"Performance bonus + joining bonus","benefits_summary":"Health insurance, stock awards, hybrid work, learning programs, wellness benefits","hiring_rounds":[{"round_number":1,"round_name":"Online Assessment","round_category":"Aptitude","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"APTI","typical_questions":"Profit and loss problems; Data interpretation with charts; Logical reasoning puzzles"},{"skill_set_code":"SQL","typical_questions":"Write a query to find second highest salary; Joins vs subqueries; Group by and having clause examples"},{"skill_set_code":"AI","typical_questions":"Basics of data analysis workflow; What is supervised vs unsupervised learning?; Use cases of predictive analytics"}]},{"round_number":2,"round_name":"Technical Interview Round 1","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"SQL","typical_questions":"Explain normalization; Write query for cumulative sum; Window functions usage"},{"skill_set_code":"AI","typical_questions":"Explain regression vs classification; What is overfitting?; Feature engineering techniques"},{"skill_set_code":"SWE","typical_questions":"Explain ETL process; Data pipeline architecture; Version control basics"}]},{"round_number":3,"round_name":"Technical Interview Round 2","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"SQL","typical_questions":"Optimize a slow query; Difference between clustered and non-clustered index; Transactions and ACID properties"},{"skill_set_code":"CLOUD","typical_questions":"What is Azure Data Factory?; Data warehousing concepts; Cloud storage types"},{"skill_set_code":"COMM","typical_questions":"Explain a dashboard you built; Communicating insights to non-technical stakeholders; Handling ambiguous requirements"}]},{"round_number":4,"round_name":"HR + Managerial Round","round_category":"Interview","evaluation_type":"HR","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COMM","typical_questions":"Tell me about yourself; Why Microsoft?; Describe a challenge you faced"},{"skill_set_code":"SWE","typical_questions":"Team collaboration experience; Handling deadlines; Learning new tools quickly"},{"skill_set_code":"APTI","typical_questions":"Situational judgment questions; Decision-making scenarios; Conflict resolution"}]}]},{"opportunity_type":"Internship","role_title":"Business Intelligence Intern (Power BI)","role_category":"Data_Analyst","job_description":"Assist in creating dashboards and reports using Power BI. Work with datasets to clean, transform, and visualize data. Support business teams in extracting insights and improving reporting efficiency.","compensation":"Stipend","ctc_or_stipend":70000,"bonus":"Potential PPO based on performance","benefits_summary":"Mentorship, flexible work, access to Microsoft learning resources, PPO opportunity","hiring_rounds":[{"round_number":1,"round_name":"Online Test","round_category":"Coding Test","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"SQL","typical_questions":"Basic select queries; Joins and aggregations; Filtering data with conditions"},{"skill_set_code":"APTI","typical_questions":"Basic quantitative aptitude; Logical puzzles; Data interpretation"},{"skill_set_code":"AI","typical_questions":"Basics of data analytics; Difference between data and information; Visualization importance"}]},{"round_number":2,"round_name":"Technical Interview","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"SQL","typical_questions":"Write query for top N records; Explain joins with examples; Group by usage"},{"skill_set_code":"AI","typical_questions":"Explain basic statistics concepts; Mean, median, mode differences; Data cleaning steps"},{"skill_set_code":"COMM","typical_questions":"Explain a project; Presenting insights; Communication clarity"}]},{"round_number":3,"round_name":"HR Round","round_category":"Interview","evaluation_type":"HR","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COMM","typical_questions":"Why this role?; Strengths and weaknesses; Career goals"},{"skill_set_code":"SWE","typical_questions":"Teamwork experience; Handling feedback; Learning new tools"},{"skill_set_code":"APTI","typical_questions":"Situational questions; Decision making; Problem-solving mindset"}]}]}]}'::jsonb);
INSERT INTO public.job_role_details_json (company_id, company_name, job_role_json) VALUES (3, 'Practo', '{"company_name":"Practo","job_role_details":[{"opportunity_type":"Employment","role_title":"Software Development Engineer (SDE I)","role_category":"SDE","job_description":"Build scalable healthcare technology solutions including appointment booking systems, patient records, and telemedicine platforms. Work on backend services, REST APIs, and database optimization while ensuring high availability and security for healthcare data.","compensation":"CTC","ctc_or_stipend":1200000,"bonus":"Performance bonus + ESOPs","benefits_summary":"Health insurance, wellness benefits, ESOPs, flexible work, learning programs","hiring_rounds":[{"round_number":1,"round_name":"Online Coding Test","round_category":"Coding Test","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"COD","typical_questions":"Two sum problem; Longest common prefix; Check if string is palindrome"},{"skill_set_code":"DSA","typical_questions":"Explain linked list operations; Stack vs queue differences; Tree traversal methods"},{"skill_set_code":"APTI","typical_questions":"Probability problems; Time and distance; Logical reasoning puzzles"}]},{"round_number":2,"round_name":"Technical Interview Round 1","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"DSA","typical_questions":"Find cycle in linked list; Binary search implementation; Find kth largest element"},{"skill_set_code":"OOD","typical_questions":"Design a hospital management system; Explain OOP principles; Design a notification system"},{"skill_set_code":"OS","typical_questions":"Process vs thread; Deadlock conditions; Memory management basics"}]},{"round_number":3,"round_name":"Technical Interview Round 2","round_category":"Interview","evaluation_type":"Technical","assessment_mode":"Online","skill_sets":[{"skill_set_code":"SYSD","typical_questions":